// 테이블 테두리 설정
const tableBorder = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const cellBorders = { top: tableBorder, bottom: tableBorder, left: tableBorder, right: tableBorder };

// 헤더 셀 생성 함수
function createHeaderCell(text) {
  return new TableCell({
    borders: cellBorders,
    shading: { fill: "2B579A", type: ShadingType.CLEAR },
    width: { size: 1560, type: WidthType.DXA },
    children: [new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ text: text, bold: true, size: 20, color: "FFFFFF" })]
    })]
  });
}

// 일반 셀 생성 함수
function createDataCell(text, alignment = AlignmentType.LEFT, bold = false) {
  return new TableCell({
    borders: cellBorders,
    width: { size: 1560, type: WidthType.DXA },
    children: [new Paragraph({
      alignment: alignment,
      children: [new TextRun({ text: text.toString(), size: 20, bold: bold })]
    })]
  });
}

