// 요약 섹션 생성 함수
function createSummarySection(data) {
  const summaryRows = [
    new TableRow({
      tableHeader: true,
      children: [
        createHeaderCell("카테고리"),
        createHeaderCell("총 인원"),
        createHeaderCell("Lv1"),
        createHeaderCell("Lv2"),
        createHeaderCell("Lv3"),
        createHeaderCell("Lv4"),
        createHeaderCell("Lv5")
      ]
    })
  ];

  Object.values(data).forEach(category => {
    const totals = { lv1: 0, lv2: 0, lv3: 0, lv4: 0, lv5: 0 };
    category.skills.forEach(skill => {
      totals.lv1 += skill.lv1;
      totals.lv2 += skill.lv2;
      totals.lv3 += skill.lv3;
      totals.lv4 += skill.lv4;
      totals.lv5 += skill.lv5;
    });

    summaryRows.push(new TableRow({
      children: [
        createDataCell(category.title, AlignmentType.LEFT, true),
        createDataCell(category.total, AlignmentType.CENTER, true),
        createDataCell(totals.lv1, AlignmentType.CENTER),
        createDataCell(totals.lv2, AlignmentType.CENTER),
        createDataCell(totals.lv3, AlignmentType.CENTER),
        createDataCell(totals.lv4, AlignmentType.CENTER),
        createDataCell(totals.lv5, AlignmentType.CENTER)
      ]
    }));
  });

  return [
    new Paragraph({
      children: [new TextRun("다음 표는 전체 기술 카테고리별 인력 현황을 요약한 것입니다:")]
    }),
    new Paragraph({ children: [new TextRun("")] }),
    new Table({
      columnWidths: [1560, 1560, 1560, 1560, 1560, 1560, 1560],
      margins: { top: 100, bottom: 100, left: 180, right: 180 },
      rows: summaryRows
    }),
    new Paragraph({ children: [new TextRun("")] })
  ];
}

// 카테고리 섹션 생성 함수
function createCategorySection(category, sectionNum) {
  const rows = [
    new TableRow({
      tableHeader: true,
      children: [
        createHeaderCell("세부 기술"),
        createHeaderCell("총 인원"),
        createHeaderCell("Lv1"),
        createHeaderCell("Lv2"),
        createHeaderCell("Lv3"),
        createHeaderCell("Lv4"),
        createHeaderCell("Lv5")
      ]
    })
  ];

  category.skills.forEach(skill => {
    rows.push(new TableRow({
      children: [
        createDataCell(skill.name, AlignmentType.LEFT),
        createDataCell(skill.total, AlignmentType.CENTER, true),
        createDataCell(skill.lv1, AlignmentType.CENTER),
        createDataCell(skill.lv2, AlignmentType.CENTER),
        createDataCell(skill.lv3, AlignmentType.CENTER),
        createDataCell(skill.lv4, AlignmentType.CENTER),
        createDataCell(skill.lv5, AlignmentType.CENTER)
      ]
    }));
  });

  return [
    new Paragraph({
      heading: HeadingLevel.HEADING_2,
      children: [new TextRun(`4.${sectionNum} ${category.title} (총 ${category.total}명)`)]
    }),
    new Paragraph({ children: [new TextRun("")] }),
    new Table({
      columnWidths: [1560, 1560, 1560, 1560, 1560, 1560, 1560],
      margins: { top: 100, bottom: 100, left: 180, right: 180 },
      rows: rows
    }),
    new Paragraph({ children: [new TextRun("")] })
  ];
}

